import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";
import "./Teacher.css";

export default function TeacherClasses() {
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [users, setUsers] = useState([]);
  const [selected, setSelected] = useState(null);
  const [students, setStudents] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [studentsLoading, setStudentsLoading] = useState(false);

  useEffect(() => {
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [clsRes, courseRes, userRes] = await Promise.all([
          api.get("/teacher/classes"),
          api.get("/courses"),
          api.get("/users"),
        ]);
        setClasses(clsRes.data.data || []);
        setCourses(courseRes.data.data || []);
        setUsers(userRes.data.data || []);
      } catch { toast.error("Không thể tải dữ liệu"); }
      finally { setLoading(false); }
    };
    fetchAll();
  }, []);

  const getCourse = (courseId) => courses.find(c => c.id === courseId || c.id === Number(courseId));

  const filtered = classes.filter(c =>
    !search ||
    c.name?.toLowerCase().includes(search.toLowerCase()) ||
    getCourse(c.courseId)?.title?.toLowerCase().includes(search.toLowerCase())
  );

  const viewStudents = async (cls) => {
    setSelected(cls);
    setStudentsLoading(true);
    try {
      const r = await api.get(`/teacher/classes/${cls.id}/students`);
      // Chỉ lấy học viên đã được duyệt (approved/enrolled)
      const approved = (r.data.data || []).filter(e =>
        ["approved", "enrolled", "completed"].includes(e.status)
      );
      setStudents(approved);
    } catch { toast.error("Không thể tải học viên"); }
    finally { setStudentsLoading(false); }
  };

  const getUserName = (userId) => {
    const u = users.find(u => u.id === userId || u.id === Number(userId));
    return u ? u.name : `ID: ${userId}`;
  };

  const getUserEmail = (userId) => {
    const u = users.find(u => u.id === userId || u.id === Number(userId));
    return u?.email || "";
  };

  const STATUS_BADGE = {
    pending: "badge-yellow", active: "badge-green",
    completed: "badge-gray", cancelled: "badge-red"
  };
  const STATUS_LABEL = {
    pending: "Chờ khai giảng", active: "Đang học",
    completed: "Đã kết thúc", cancelled: "Đã hủy"
  };
  const ENROLL_BADGE = {
    approved: "badge-blue", enrolled: "badge-green",
    completed: "badge-gray"
  };
  const ENROLL_LABEL = {
    approved: "Đã duyệt", enrolled: "Đang học", completed: "Hoàn thành"
  };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Lớp của tôi</h1>
        <p>Các lớp học được phân công giảng dạy</p>
      </div>

      <div className="toolbar">
        <input className="search-input" placeholder="🔍 Tìm theo tên lớp, khóa học..."
          value={search} onChange={e => setSearch(e.target.value)} />
        <span style={{ fontSize: "0.82rem", color: "var(--gray-500)" }}>
          {filtered.length} lớp
        </span>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: selected ? "1fr 1.2fr" : "1fr", gap: 20 }}>
        {/* Danh sách lớp */}
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {loading ? <div className="page-loading"><div className="spinner" /></div> :
            filtered.length === 0 ? <div className="empty-state"><p>Chưa có lớp nào</p></div> :
            filtered.map(cls => {
              const course = getCourse(cls.courseId);
              const isSelected = selected?.id === cls.id;
              return (
                <div key={cls.id} className={`teacher-class-card ${isSelected ? "selected" : ""}`}
                  onClick={() => viewStudents(cls)}>
                  <div className="class-card-top">
                    <div>
                      <h4>{cls.name}</h4>
                      <p className="class-course-name">
                        {course && <span className={`badge ${course.examType === "IELTS" ? "badge-blue" : course.examType === "TOEIC" ? "badge-green" : "badge-gray"}`}>{course.examType}</span>}
                        <span style={{ marginLeft: 6 }}>{course?.title || "—"}</span>
                      </p>
                    </div>
                    <span className={`badge ${STATUS_BADGE[cls.status]}`}>{STATUS_LABEL[cls.status]}</span>
                  </div>
                  <div className="class-card-meta">
                    <span>👥 {cls.currentStudents || 0}/{cls.maxStudents} học viên</span>
                    <span>📅 {cls.startDate ? new Date(cls.startDate).toLocaleDateString("vi-VN") : "—"} → {cls.endDate ? new Date(cls.endDate).toLocaleDateString("vi-VN") : "—"}</span>
                  </div>
                  {cls.description && (
                    <p className="class-card-desc">{cls.description}</p>
                  )}
                </div>
              );
            })
          }
        </div>

        {/* Danh sách học viên */}
        {selected && (
          <div className="section-card" style={{ height: "fit-content", position: "sticky", top: 80 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <div>
                <h3 className="section-title" style={{ margin: 0 }}>
                  Học viên — {selected.name}
                </h3>
                <p style={{ fontSize: "0.78rem", color: "var(--gray-500)", marginTop: 2 }}>
                  {students.length} học viên đã được duyệt (tính vào sĩ số)
                </p>
              </div>
              <button className="btn btn-ghost btn-sm" onClick={() => setSelected(null)}>✕</button>
            </div>

            {studentsLoading ? <div className="page-loading"><div className="spinner" /></div> :
              students.length === 0
                ? <div className="empty-state"><p>Chưa có học viên được duyệt</p></div>
                : students.map(s => (
                  <div key={s.id} className="student-item">
                    <div className="avatar" style={{ flexShrink: 0 }}>
                      {getUserName(s.userId)?.charAt(0)?.toUpperCase()}
                    </div>
                    <div style={{ flex: 1, overflow: "hidden" }}>
                      <p style={{ fontWeight: 600, fontSize: "0.875rem" }}>{getUserName(s.userId)}</p>
                      <p style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>{getUserEmail(s.userId)}</p>
                    </div>
                    <div style={{ textAlign: "right", flexShrink: 0 }}>
                      <span className={`badge ${ENROLL_BADGE[s.status] || "badge-gray"}`}>
                        {ENROLL_LABEL[s.status] || s.status}
                      </span>
                      <div style={{ marginTop: 4, display: "flex", alignItems: "center", gap: 6 }}>
                        <div style={{ width: 60, height: 4, background: "var(--gray-100)", borderRadius: 2, overflow: "hidden" }}>
                          <div style={{ height: "100%", width: `${s.progress || 0}%`, background: "var(--primary)", borderRadius: 2 }} />
                        </div>
                        <span style={{ fontSize: "0.7rem", color: "var(--gray-500)" }}>{s.progress || 0}%</span>
                      </div>
                    </div>
                  </div>
                ))
            }
          </div>
        )}
      </div>
    </div>
  );
}
